import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.net.MalformedURLException;
import java.net.URL;

public class RedirectService {

    public void performRedirect(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String returnUrl = request.getParameter("returnUrl");

        // Trim whitespace from returnUrl if present
        if (returnUrl != null) {
            returnUrl = returnUrl.trim();
        }

        // Handle empty or null returnUrl by redirecting to context root
        if (returnUrl == null || returnUrl.isEmpty()) {
            response.sendRedirect(request.getContextPath());
            return;
        }

        boolean isValidRedirectUrl = validateRedirectUrl(request, returnUrl);

        if (isValidRedirectUrl) {
            response.sendRedirect(returnUrl);
        } else {
            // Redirect to context root as safe default for invalid URLs
            response.sendRedirect(request.getContextPath());
        }
    }

    /**
     * Validates that the redirect URL is safe:
     * - Either a relative URL (no protocol)
     * - Or an absolute URL with the same origin (scheme, host, port) as the request
     */
    private boolean validateRedirectUrl(HttpServletRequest request, String url) {
        try {
            URL redirectUrl = new URL(url);
            String requestScheme = request.getScheme();
            String requestHost = request.getServerName();
            int requestPort = getEffectivePort(request.getScheme(), request.getServerPort());

            String urlScheme = redirectUrl.getProtocol();
            String urlHost = redirectUrl.getHost();
            int urlPort = getEffectivePort(urlScheme, redirectUrl.getPort());

            // Check same origin components
            return urlScheme.equalsIgnoreCase(requestScheme)
                    && urlHost.equalsIgnoreCase(requestHost)
                    && urlPort == requestPort;
        } catch (MalformedURLException e) {
            // Relative URL is considered safe
            return true;
        }
    }

    /**
     * Gets the effective port, using default ports if the port is not specified (=-1)
     */
    private int getEffectivePort(String scheme, int port) {
        if (port == -1) {
            return "https".equalsIgnoreCase(scheme) ? 443 : 80;
        }
        return port;
    }
}
